#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5;
int s,n,m,num[MAXN][MAXN],num0[MAXN][MAXN],f[20005], ans;
signed main(void)
{
	s=read(),n=read(),m=read();
	FOR(i,1,s)
	{
		FOR(j,1,n)
		{
			num[j][i]=read();
		}
	}
	FOR(i,1,n)
	{
		sort(num[i]+1,num[i]+s+1);
		FOR(j,1,s)
		{
			num0[i][j]=num[i][j]*2+1;
		}
	}
	FOR(i,1,n)
	{
		ROF(j,m,0)
		{
			for(int k=0;k<=s&&j>=num0[i][k];++k)
			{
				f[j]=max(f[j],f[j-num0[i][k]]+k*i);
			}
		}
	}
	write(f[m]);
	return false;
}
